<?php declare(strict_types=1); namespace App\Http\Controllers\Payroll; use App\Http\Controllers\Controller; use App\Models\Payroll\PayrollAdjustment; use App\Models\Payroll\PayrollItem; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\View\View; class PayrollAdjustmentController extends Controller{public function index():View{return view('payroll.adjustments.index',['title'=>'Penyesuaian Payroll','adjustments'=>PayrollAdjustment::with('payrollItem')->latest()->paginate(15)]);} public function store(Request $r,PayrollItem $item):RedirectResponse{$data=$r->validate(['adjustment_type'=>'required|in:earning,deduction','amount'=>'required|integer|min:1','reason'=>'required|string|min:5']);$adj=$item->adjustments()->create($data+['created_by'=>$r->user()->id,'approved_by'=>$r->user()->id,'approved_at'=>now()]);$item->components()->create(['component_name_snapshot'=>'Penyesuaian Manual','component_type'=>$data['adjustment_type'],'calculation_type_snapshot'=>'manual','amount'=>$data['amount'],'is_manual_adjustment'=>true,'source_type'=>'payroll_adjustment','source_id'=>$adj->id,'notes'=>$data['reason']]);$data['adjustment_type']==='deduction'?$item->increment('total_deductions',$data['amount']):$item->increment('gross_salary',$data['amount']);$item->update(['net_salary'=>max(0,$item->gross_salary-$item->total_deductions)]);return back()->with('status','Penyesuaian payroll disimpan.');}}
